/*
 * coshf() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly coshf  (test_coshf_opt.elf)
 *   2. Linked with toolchain's default coshf        (test_coshf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += coshf(vx);
#else
    float r = coshf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* smallest normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 (ULP density) (8) --- */
    emit_u(0x3f7fffffu);          /* one ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);          /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);          /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);          /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);          /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);          /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3f000000u);          /* 0.5 */
    emit_u(0x3f000001u);          /* one ULP above 0.5 */
    emit_u(0x40000000u);          /* 2.0 */
    emit_u(0x3fffffffu);          /* one ULP below 2.0 */
    emit_u(0x40800000u);          /* 4.0 */
    emit_u(0x3e800000u);          /* 0.25 */

    /* --- Section 6: Hyperbolic-specific mathematical constants (14) --- */
    /* cosh is even, so cosh(x) == cosh(-x); test both signs */
    emit_u(0x3f317218u);          /* ln2 ~ 0.6931: cosh(ln2) = 1.25 exactly */
    emit_u(0xbf317218u);          /* -ln2 */
    emit(0.5f);                   /* cosh(0.5) ~ 1.1276 */
    emit(-0.5f);
    emit(1.5f);                   /* cosh(1.5) ~ 2.3524 */
    emit(-1.5f);
    emit(2.0f);                   /* cosh(2) ~ 3.7622 */
    emit(-2.0f);
    emit_u(0x3f490fdbu);          /* pi/4 ~ 0.7854 */
    emit_u(0xbf490fdbu);          /* -pi/4 */
    emit_u(0x3fc90fdbu);          /* pi/2 ~ 1.5708 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0x40490fdbu);          /* pi ~ 3.1416 */
    emit_u(0xc0490fdbu);          /* -pi */

    /* --- Section 7: Overflow threshold ULP neighbors (8) --- */
    /* coshf overflows near x ~ 88.7229 (0x42b17218) */
    emit_u(0x42b17217u);          /* one ULP below overflow threshold */
    emit_u(0x42b17218u);          /* exp overflow threshold ~ 88.7229 */
    emit_u(0x42b17219u);          /* one ULP above overflow threshold */
    emit_u(0x42b17210u);          /* a few ULPs below threshold */
    emit_u(0xc2b17217u);          /* negative: one ULP above -threshold */
    emit_u(0xc2b17218u);          /* -threshold */
    emit_u(0xc2b17219u);          /* one ULP below -threshold */
    emit_u(0xc2b17210u);          /* a few ULPs below -threshold */

    /* --- Section 8: Large arguments near overflow (8) --- */
    emit(10.0f);
    emit(-10.0f);
    emit(20.0f);
    emit(-20.0f);
    emit(50.0f);
    emit(80.0f);
    emit(88.0f);
    emit(-88.0f);

    /* --- Section 9: Small-argument fast-path (cosh(x)~1) (8) --- */
    /* For tiny x, cosh(x) = 1 + x^2/2 + ...; test power-of-2 thresholds */
    emit_u(0x39800000u);          /* 2^-12 ~ 2.44e-4 */
    emit_u(0xb9800000u);          /* -2^-12 */
    emit_u(0x3d800000u);          /* 2^-4 = 0.0625 */
    emit_u(0xbd800000u);          /* -2^-4 */
    emit_u(0x33800000u);          /* 2^-24 ~ 5.96e-8, near epsilon */
    emit_u(0xb3800000u);          /* -2^-24 */
    emit(1.0e-20f);
    emit(-1.0e-20f);

    /* --- Section 10: Hard and branch-coverage cases (29) --- */
    /* Eighth-interval boundaries */
    emit(0.125f);
    emit(-0.125f);
    emit(0.25f);
    emit(-0.25f);
    emit(0.375f);
    emit(-0.375f);
    emit(0.625f);
    emit(-0.625f);
    emit(0.75f);
    emit(-0.75f);
    emit(0.875f);
    emit(-0.875f);
    /* Mid-range polynomial stress */
    emit(3.0f);
    emit(-3.0f);
    emit(4.0f);
    emit(-4.0f);
    emit(5.0f);
    emit(-5.0f);
    emit(8.0f);
    emit(-8.0f);
    emit(16.0f);
    emit(-16.0f);
    emit(64.0f);
    emit(-64.0f);
    /* Just past overflow -- result is +Inf */
    emit(100.0f);
    emit(-100.0f);
    emit_u(0x7f7fffffu);          /* FLT_MAX: guaranteed overflow */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    /* Near-zero boundary: 1 ULP above zero */
    emit_u(0x00000002u);          /* 2 * min subnormal */
}

/* ------------------------------------------------------------------ */
/* Dense sweep and exhaustive small (accuracy path only)              */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 88.7] and [-88.7, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 88.7f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
